-                begun.output.push_str(line);
-                begun.output.push('\n');
+                if begun.output.len() + line.len() + 1 > MAX_GUARDED_OUTPUT_LEN {
+                    log::warn!(
+                        "tmux CC guarded output exceeded {} byte cap, discarding block",
+                        MAX_GUARDED_OUTPUT_LEN
+                    );
+                    self.begun.take();
+                } else {
+                    begun.output.push_str(line);
+                    begun.output.push('\n');
+                }
                 None
             }
         };
